{
  "name": "hello-colors-app",
  "version": "1.0.0",
  "description": "Express + Tailwind project (build configured to emit compiled CSS to public/dist)",
  "main": "src/index.js",
  "scripts": {
    "start": "node src/index.js",
    "dev": "concurrently \"nodemon src/index.js\" \"tailwindcss -i ./src/styles.css -o ./public/dist/styles.css --watch\"",
    "build:css": "tailwindcss -i ./src/styles.css -o ./public/dist/styles.css --minify",
    "test": "node ./tests/test.js"
  },
  "keywords": [],
  "author": "",
  "license": "MIT",
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "concurrently": "^7.6.0",
    "nodemon": "^2.0.22",
    "tailwindcss": "^3.4.8"
  }
}

@tailwind base;
@tailwind components;
@tailwind utilities;

/* Add any custom styles here. The frontend UI will let you change text color via inline style. */

const express = require('express');
const path = require('path');

const app = express();
app.use(express.json());

// Serve static files from public
app.use(express.static(path.join(__dirname, '..', 'public')));

// In-memory color state. Default to black.
let currentColor = '#000000';

// GET current color
app.get('/api/color', (req, res) => {
  res.json({ color: currentColor });
});

// POST update color. Expect JSON: { color: "#rrggbb" }
app.post('/api/color', (req, res) => {
  const { color } = req.body || {};
  if (typeof color !== 'string') {
    return res.status(400).json({ error: 'color must be a string' });
  }
  // Basic validation: accept hex colors like #fff or #ffffff
  const hexRegex = /^#([0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})$/;
  if (!hexRegex.test(color)) {
    return res.status(400).json({ error: 'color must be a hex string like #ff0000' });
  }
  currentColor = color;
  res.json({ color: currentColor });
});

module.exports = app;

const app = require('./server');

const PORT = process.env.PORT || 3000;

if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server listening on http://localhost:${PORT}`);
  });
}

module.exports = app;

const http = require('http');
const assert = require('assert');
const app = require('../src/server');

function listenOnRandomPort(app) {
  return new Promise((resolve, reject) => {
    const server = app.listen(0, () => {
      const port = server.address().port;
      resolve({ server, port });
    }).on('error', reject);
  });
}

function httpGet(port, path) {
  return new Promise((resolve, reject) => {
    const req = http.get({ hostname: '127.0.0.1', port, path, agent: false }, (res) => {
      let body = '';
      res.setEncoding('utf8');
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => resolve({ statusCode: res.statusCode, body, headers: res.headers }));
    });
    req.on('error', reject);
  });
}

function httpPostJson(port, path, obj) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(obj);
    const req = http.request({ hostname: '127.0.0.1', port, path, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(data) } }, (res) => {
      let body = '';
      res.setEncoding('utf8');
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => resolve({ statusCode: res.statusCode, body, headers: res.headers }));
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

(async () => {
  console.log('Starting tests...');
  const { server, port } = await listenOnRandomPort(app);
  try {
    // 1) GET /api/color should return JSON with color field
    const res1 = await httpGet(port, '/api/color');
    assert.strictEqual(res1.statusCode, 200, 'GET /api/color should return 200');
    const parsed1 = JSON.parse(res1.body);
    assert.ok(typeof parsed1.color === 'string', 'GET /api/color should return { color: string }');

    // 2) POST /api/color with invalid payload should return 400
    const bad = await httpPostJson(port, '/api/color', { color: 'not-a-color' });
    assert.strictEqual(bad.statusCode, 400, 'POST /api/color with invalid color should return 400');

    // 3) POST /api/color with valid hex should update it
    const newColor = '#ff00aa';
    const ok = await httpPostJson(port, '/api/color', { color: newColor });
    assert.strictEqual(ok.statusCode, 200, 'POST /api/color with valid color should return 200');
    const parsedOk = JSON.parse(ok.body);
    assert.strictEqual(parsedOk.color.toLowerCase(), newColor, 'POST /api/color should return the new color');

    // 4) GET /api/color should now return the updated value
    const res2 = await httpGet(port, '/api/color');
    const parsed2 = JSON.parse(res2.body);
    assert.strictEqual(parsed2.color.toLowerCase(), newColor, 'GET /api/color should reflect updated color');

    // 5) Static root should serve index.html that contains "Hello World"
    const root = await httpGet(port, '/');
    assert.strictEqual(root.statusCode, 200, 'GET / should return 200');
    assert.ok(root.body.includes('Hello World'), 'index.html should contain Hello World');

    console.log('All tests passed');
    process.exit(0);
  } catch (err) {
    console.error('Test failed:', err && err.stack ? err.stack : err);
    process.exitCode = 1;
  } finally {
    server.close();
  }
})();
